export type HarthmereNamedNpcV44 = (typeof HARTHMERE_NAMED_NPCS_V44)[number];

export const HARTHMERE_NPC_ANIMAL_WEAPON_POLICY_V44 = {
  version: "harthmere-animal-no-weapon-policy-v44",
  animalKindMustHaveNoWeapons: true,
  animalAssetPrefixes: ["animal_"] as const,
} as const;

export function harthmereNamedNpcActorAssetV44(npc: HarthmereNamedNpcV44): string {
  return npc.spawn.asset;
}

export function harthmereNamedNpcByIdV44(id: string): HarthmereNamedNpcV44 | undefined {
  return HARTHMERE_NAMED_NPCS_V44.find((npc) => npc.id === id);
}

export function harthmereNamedNpcRouteForHourV44(npc: HarthmereNamedNpcV44, hour: number) {
  const entries = npc.route.schedule;
  let current = entries[0];
  for (const entry of entries) {
    if (hour >= entry.hour) current = entry;
  }
  return current;
}

export function harthmereNamedNpcIsGuardV44(npc: HarthmereNamedNpcV44): boolean {
  return npc.route.routeStyle === "guard_patrol" || npc.role === "guard";
}
